import{_ as e}from"./plugin-vue_export-helper-x3n3nnut.js";import{r as p,o as l,c as o,a as n,b as s,d as t,e as i}from"./app-uyb0nfWQ.js";const c={},u=n("h1",{id:"python数据容器-五",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#python数据容器-五","aria-hidden":"true"},"#"),s(" Python数据容器(五)")],-1),r={href:"https://blog.csdn.net/m0_66570338/article/details/128714062",target:"_blank",rel:"noopener noreferrer"},d={href:"https://download.csdn.net/download/m0_66570338/90058557",target:"_blank",rel:"noopener noreferrer"},k=n("h3",{id:"一-数据容器",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#一-数据容器","aria-hidden":"true"},"#"),s(" 一.数据容器")],-1),m={href:"https://so.csdn.net/so/search?q=%E6%95%B0%E6%8D%AE%E7%B1%BB%E5%9E%8B&spm=1001.2101.3001.7020",target:"_blank",rel:"noopener noreferrer"},v=i(`<ul><li>每一个元素，可以是<strong>任意类型</strong>的据数，如字符串、数字、布尔等</li><li>根据特点的不同可分为5类:列表（list）、元组（tuple）、字符串（str）、集合（set）、字典（dict）</li></ul><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/d0a0a4f75b8a733ead150edd58c0e548.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><hr><h3 id="二-列表-list" tabindex="-1"><a class="header-anchor" href="#二-列表-list" aria-hidden="true">#</a> 二.列表(list)</h3><blockquote><p>列表内的每一个数据，称之为元素</p></blockquote><h4 id="_1-基本格式" tabindex="-1"><a class="header-anchor" href="#_1-基本格式" aria-hidden="true">#</a> (1) 基本格式</h4><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 定义列表</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">[</span>元素<span class="token number">1</span><span class="token punctuation">,</span> 元素<span class="token number">2</span><span class="token punctuation">,</span> 元素<span class="token number">3</span><span class="token punctuation">,</span> 元素<span class="token number">4</span><span class="token punctuation">,</span> 元素<span class="token number">5</span><span class="token punctuation">]</span>
<span class="token comment"># 定义空列表</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>
变量名称 <span class="token operator">=</span> <span class="token builtin">list</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>以中括号 [] 作为标识</li><li>列表内每一个元素之间用, 逗号隔开</li><li>列表可以一次存储多个数据，且可以为<strong>不同的数据类型</strong>，支持嵌套</li><li>使用示例:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list_1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token string">&quot;guanzhi&quot;</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
my_list_2 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list_2<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_list_1<span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 输出</span>
<span class="token comment"># [&#39;观止&#39;, 20, True]</span>
<span class="token comment"># &lt;class &#39;list&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-列表的下标-索引" tabindex="-1"><a class="header-anchor" href="#_2-列表的下标-索引" aria-hidden="true">#</a> (2) 列表的下标（索引）</h4><blockquote><p>我们可以使用下标索引从列表中取出特定位置的数据</p></blockquote><ul><li>列表中的每一个元素，都有其对应位置下标索引</li><li>要注意下标索引的取值范围(有值的位置)，超出范围(没值的位置)无法取出元素，并且会报错</li><li>语法：变量 = 列表[下标索引]</li></ul><h5 id="_2-1-正向索引" tabindex="-1"><a class="header-anchor" href="#_2-1-正向索引" aria-hidden="true">#</a> (2.1) 正向索引</h5><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/2a6185062e17869ab35a7997dbb7493a.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li><strong>从前向后</strong>的方向，从<strong>0</strong>开始，依次递增</li><li>使用示例:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 语法： 列表[下标索引]</span>
my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;杜甫&quot;</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 李白</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 章北海</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 杜甫</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-2-反向索引" tabindex="-1"><a class="header-anchor" href="#_2-2-反向索引" aria-hidden="true">#</a> (2.2) 反向索引</h5><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/72693c1335207d5ca829c06b524a11a0.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li><strong>从后向前</strong>：从**-1**开始，依次递减（-1、-2、-3…）</li><li>使用示例:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;杜甫&quot;</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 杜甫</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token operator">-</span><span class="token number">2</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 章北海</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token operator">-</span><span class="token number">3</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 李白</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-3-嵌套列表的索引" tabindex="-1"><a class="header-anchor" href="#_2-3-嵌套列表的索引" aria-hidden="true">#</a> (2.3) 嵌套列表的索引</h5><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/f7f1c54bb0000b4159b0137f40a0f33b.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>如果列表是嵌套的列表，同样支持下标索引，且用法与上述类似</li><li>使用示例:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 语法： 列表[外层列表下标索引][内层列表下标索引]</span>
my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;杜甫&quot;</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 李白</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 章北海</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 罗辑</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 杜甫</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-列表的常用操作" tabindex="-1"><a class="header-anchor" href="#_3-列表的常用操作" aria-hidden="true">#</a> (3) 列表的常用操作</h4><blockquote><p>列表提供了一系列方法：如果将函数定义为class（类）的成员，那么函数称之为：方法</p></blockquote><table><thead><tr><th style="text-align:left;">使用方式</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td style="text-align:left;">列表.append(元素)</td><td style="text-align:left;">向列表中追加一个元素</td></tr><tr><td style="text-align:left;">列表.extend(容器)</td><td style="text-align:left;">将数据容器的内容依次取出，追加到列表尾部</td></tr><tr><td style="text-align:left;">列表.insert(下标, 元素)</td><td style="text-align:left;">在指定下标处，插入指定的元素</td></tr><tr><td style="text-align:left;">del 列表[下标]</td><td style="text-align:left;">删除列表指定下标元素</td></tr><tr><td style="text-align:left;">列表.pop(下标)</td><td style="text-align:left;">删除列表指定下标元素</td></tr><tr><td style="text-align:left;">列表.remove(元素)</td><td style="text-align:left;">从前向后，删除此元素第一个匹配项</td></tr><tr><td style="text-align:left;">列表.clear()</td><td style="text-align:left;">清空列表</td></tr><tr><td style="text-align:left;">列表.count(元素)</td><td style="text-align:left;">统计此元素在列表中出现的次数</td></tr><tr><td style="text-align:left;">列表.index(元素)</td><td style="text-align:left;">查找指定元素在列表的下标 找不到报错ValueError</td></tr><tr><td style="text-align:left;">len(列表)</td><td style="text-align:left;">统计容器内有多少元素</td></tr></tbody></table><ul><li>不需要硬记下来,有一个模糊印象，知晓有这样的用法,需要的时候，随时查阅资料即可</li></ul><h5 id="_3-1-查询元素" tabindex="-1"><a class="header-anchor" href="#_3-1-查询元素" aria-hidden="true">#</a> (3.1) 查询元素</h5><blockquote><p>查找某元素的下标</p></blockquote><ul><li>查找指定元素在列表的下标，如果找不到，报错ValueError</li><li>语法：列表.index(元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;杜甫&quot;</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">.</span>index<span class="token punctuation">(</span><span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># 打印 2</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">.</span>index<span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># 打印 ValueError: &#39;观止&#39; is not in list</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-2-修改元素" tabindex="-1"><a class="header-anchor" href="#_3-2-修改元素" aria-hidden="true">#</a> (3.2) 修改元素</h5><blockquote><p>修改特定位置（索引）的元素值</p></blockquote><ul><li>直接对指定下标（正向、反向下标均可）的值进行：重新赋值（修改）</li><li>语法一：列表[下标] = 值</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;杜甫&quot;</span><span class="token punctuation">]</span>
my_list<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string">&quot;观止&quot;</span>
my_list<span class="token punctuation">[</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token string">&quot;study&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span> <span class="token comment"># 打印 [&#39;观止&#39;, &#39;章北海&#39;, &#39;罗辑&#39;, &#39;study&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-3-插入元素" tabindex="-1"><a class="header-anchor" href="#_3-3-插入元素" aria-hidden="true">#</a> (3.3) 插入元素</h5><blockquote><p>在指定的下标位置，插入指定的元素</p></blockquote><ul><li>语法：列表.insert(下标, 元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">]</span>
my_list<span class="token punctuation">.</span>insert<span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span> <span class="token comment"># 打印 [&#39;李白&#39;, &#39;观止&#39;, &#39;章北海&#39;, &#39;罗辑&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-4-追加元素" tabindex="-1"><a class="header-anchor" href="#_3-4-追加元素" aria-hidden="true">#</a> (3.4) 追加元素</h5><blockquote><p>将指定元素，追加到列表的尾部</p></blockquote><ul><li>语法一：列表.append(元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">]</span>
my_list<span class="token punctuation">.</span>append<span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span> <span class="token comment"># 打印 [&#39;李白&#39;, &#39;章北海&#39;, &#39;罗辑&#39;, &#39;观止&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>语法一：列表.extend(其它数据容器)</li><li>将其它数据容器的内容取出，依次追加到列表尾部</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list_1 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">]</span>
my_list_2 <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">]</span>
my_list_1<span class="token punctuation">.</span>extend<span class="token punctuation">(</span>my_list_2<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list_1<span class="token punctuation">)</span> <span class="token comment"># 打印 [&#39;李白&#39;, &#39;章北海&#39;, &#39;罗辑&#39;, &#39;观止&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-5-删除元素" tabindex="-1"><a class="header-anchor" href="#_3-5-删除元素" aria-hidden="true">#</a> (3.5) 删除元素</h5><ul><li>语法一:del 列表[下标]</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">]</span>
<span class="token keyword">del</span> my_list<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span> <span class="token comment"># 打印 [&#39;章北海&#39;, &#39;罗辑&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>语法二:列表.pop(下标)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">]</span>
my_list<span class="token punctuation">.</span>pop<span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span> <span class="token comment"># 打印 [&#39;章北海&#39;, &#39;罗辑&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>语法三:列表.remove(元素)</li><li>删除某元素在列表中的<strong>第一个</strong>匹配项</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;李白&quot;</span><span class="token punctuation">]</span>
my_list<span class="token punctuation">.</span>remove<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span> <span class="token comment"># 打印 [&#39;章北海&#39;, &#39;罗辑&#39;, &#39;李白&#39;]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-6-清空列表内容" tabindex="-1"><a class="header-anchor" href="#_3-6-清空列表内容" aria-hidden="true">#</a> (3.6) 清空列表内容</h5><ul><li>语法:列表.clear()</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">]</span>
my_list<span class="token punctuation">.</span>clear<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span> <span class="token comment"># 打印 []</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-7-统计某元素在列表内的数量" tabindex="-1"><a class="header-anchor" href="#_3-7-统计某元素在列表内的数量" aria-hidden="true">#</a> (3.7) 统计某元素在列表内的数量</h5><ul><li>语法:列表.count(元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;李白&quot;</span><span class="token punctuation">]</span>
num <span class="token operator">=</span> my_list<span class="token punctuation">.</span>count<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span> <span class="token comment"># 打印 2</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-8-统计列表内有多少元素" tabindex="-1"><a class="header-anchor" href="#_3-8-统计列表内有多少元素" aria-hidden="true">#</a> (3.8) 统计列表内有多少元素</h5><ul><li>语法:len(列表)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;章北海&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;李白&quot;</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># 打印 4</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-列表的遍历" tabindex="-1"><a class="header-anchor" href="#_4-列表的遍历" aria-hidden="true">#</a> (4) 列表的遍历</h4><blockquote><p>将容器内的元素依次取出进行处理的行为，称之为：遍历、迭代。</p></blockquote><ul><li>可以使用循环遍历列表的元素</li><li>通过列表[下标]的方式在循环中取出列表的元素</li><li>循环条件为 下标值 &lt; 列表的元素数量</li></ul><h5 id="_4-1-while循环遍历" tabindex="-1"><a class="header-anchor" href="#_4-1-while循环遍历" aria-hidden="true">#</a> (4.1) while循环遍历</h5><ul><li>基本格式</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>index <span class="token operator">=</span> <span class="token number">0</span>
<span class="token keyword">while</span> index <span class="token operator">&lt;</span> <span class="token builtin">len</span><span class="token punctuation">(</span>列表<span class="token punctuation">)</span><span class="token punctuation">:</span>
    元素 <span class="token operator">=</span> 列表<span class="token punctuation">[</span>index<span class="token punctuation">]</span>
<span class="token comment">#    对元素进行处理</span>
    index <span class="token operator">+=</span> <span class="token number">1</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>使用示例：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span><span class="token number">2</span><span class="token punctuation">,</span><span class="token number">3</span><span class="token punctuation">,</span><span class="token number">4</span><span class="token punctuation">]</span>
index <span class="token operator">=</span> <span class="token number">0</span>
<span class="token keyword">while</span> index <span class="token operator">&lt;</span> <span class="token builtin">len</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span><span class="token punctuation">:</span>
    num <span class="token operator">=</span> my_list<span class="token punctuation">[</span>index<span class="token punctuation">]</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span>
    index <span class="token operator">+=</span> <span class="token number">1</span> 
<span class="token comment"># 输出</span>
<span class="token comment"># 1</span>
<span class="token comment"># 2</span>
<span class="token comment"># 3</span>
<span class="token comment"># 4</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_4-2-for循环遍历" tabindex="-1"><a class="header-anchor" href="#_4-2-for循环遍历" aria-hidden="true">#</a> (4.2) for循环遍历</h5><ul><li>依次取出元素并赋值到临时变量上,在每一次的循环中，可以对临时变量（元素）进行处理。</li><li>基本格式：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">for</span> 临时变量 <span class="token keyword">in</span> 数据容器<span class="token punctuation">:</span>
    对临时变量（元素）进行处理
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>使用示例：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span>
<span class="token keyword">for</span> x <span class="token keyword">in</span> my_list<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>x<span class="token punctuation">)</span>
<span class="token comment"># 输出</span>
<span class="token comment"># 1</span>
<span class="token comment"># 2</span>
<span class="token comment"># 3</span>
<span class="token comment"># 4</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_4-3-for与while对比" tabindex="-1"><a class="header-anchor" href="#_4-3-for与while对比" aria-hidden="true">#</a> (4.3) for与while对比</h5><ul><li>在循环控制上： <ul><li>while循环可以自定循环条件，并自行控制</li><li>for循环不可以自定循环条件，只可以一个个从容器内取出数据</li></ul></li><li>在无限循环上： <ul><li>while循环可以通过条件控制做到无限循环</li><li>for循环理论上不可以，因为被遍历的容器容量不是无限的</li></ul></li><li>在使用场景上： <ul><li>while循环适用于任何想要循环的场景</li><li>for循环适用于，遍历数据容器的场景或简单的固定次数循环场景</li></ul></li></ul><h4 id="_5-列表小结" tabindex="-1"><a class="header-anchor" href="#_5-列表小结" aria-hidden="true">#</a> (5) 列表小结</h4><ul><li>列表特点: <ul><li>可以容纳多个元素（上限为2**63-1、9223372036854775807个）</li><li>可以容纳不同类型的元素（混装）</li><li>数据是有序存储的（有下标序号）</li><li>允许重复数据存在</li><li>可以修改（增加或删除元素等）</li></ul></li></ul><hr><h3 id="三-元组-tuple" tabindex="-1"><a class="header-anchor" href="#三-元组-tuple" aria-hidden="true">#</a> 三.元组(tuple)</h3><blockquote><p>元组同列表一样,但一旦定义完成，就不可修改</p></blockquote><h4 id="_1-基本格式-1" tabindex="-1"><a class="header-anchor" href="#_1-基本格式-1" aria-hidden="true">#</a> (1) 基本格式</h4><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 定义元组</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">(</span>元素<span class="token number">1</span><span class="token punctuation">,</span> 元素<span class="token number">2</span><span class="token punctuation">,</span> 元素<span class="token number">3</span><span class="token punctuation">,</span> 元素<span class="token number">4</span><span class="token punctuation">,</span> 元素<span class="token number">5</span><span class="token punctuation">)</span>
<span class="token comment"># 定义只有一个元素的元组</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">(</span>元素<span class="token number">1</span><span class="token punctuation">,</span><span class="token punctuation">)</span>
<span class="token comment"># 定义空元组</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span>
变量名称 <span class="token operator">=</span> <span class="token builtin">tuple</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>以小括号 () 作为标识</li><li>列表内每一个元素之间用, 逗号隔开</li><li>列表可以一次存储多个数据，且可以为<strong>不同的数据类型</strong>，支持嵌套</li><li>使用示例:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple_1 <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token string">&quot;guanzhi&quot;</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
my_tuple_2 <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_tuple_2<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_tuple_1<span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token comment"># 输出</span>
<span class="token comment"># (&#39;观止&#39;, 20, True)</span>
<span class="token comment"># &lt;class &#39;tuple&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>元组只有一个数据，这个数据后面要<strong>添加逗号</strong>，否则不是元组</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token comment"># 打印 &lt;class &#39;str&#39;&gt;</span>
my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;tuple&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>嵌套元组使用:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 获取值方式与列表一致</span>
my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">,</span> <span class="token number">6</span><span class="token punctuation">)</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment"># 打印 1</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-元组的常用操作" tabindex="-1"><a class="header-anchor" href="#_2-元组的常用操作" aria-hidden="true">#</a> (2) 元组的常用操作</h4><blockquote><p>元组由于不可修改的特性，所以其操作方法非常少。</p></blockquote><table><thead><tr><th style="text-align:left;">方法</th><th style="text-align:left;">作用</th></tr></thead><tbody><tr><td style="text-align:left;">元组.index(元素)</td><td style="text-align:left;">查找某个数据，如果数据存在返回对应的下标，否则报错</td></tr><tr><td style="text-align:left;">元组.count(元素)</td><td style="text-align:left;">统计某个数据在当前元组出现的次数</td></tr><tr><td style="text-align:left;">len(元组)</td><td style="text-align:left;">统计元组内的元素个数</td></tr></tbody></table><h5 id="_2-1-查询元素" tabindex="-1"><a class="header-anchor" href="#_2-1-查询元素" aria-hidden="true">#</a> (2.1) 查询元素</h5><ul><li>根据下标(索引)取出数据</li><li>语法：元组[下标索引]</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token number">20</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 观止</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>查找特定元素的第一个匹配项</li><li>语法：元组.index(元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">.</span>index<span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 0</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-2-统计操作" tabindex="-1"><a class="header-anchor" href="#_2-2-统计操作" aria-hidden="true">#</a> (2.2) 统计操作</h5><ul><li>统计某个数据在元组内出现次数</li><li>语法一：元组.count(元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">.</span>count<span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 2</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>统计元组内元素个数</li><li>语法二：len(元组)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 3</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-3-注意事项" tabindex="-1"><a class="header-anchor" href="#_2-3-注意事项" aria-hidden="true">#</a> (2.3) 注意事项</h5><ul><li>不可以修改元组的内容，否则会直接报错</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
my_tuple<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">5</span> <span class="token comment"># 报错 &#39;tuple&#39; object does not support item assignment</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>可以修改元组内的list的内容（修改元素、增加、删除、反转等）</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
my_tuple<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">5</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span> <span class="token comment"># 打印 (1, True, [5, 3, 4])</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不可以替换list为其它list或其它类型</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
my_tuple<span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span> <span class="token comment"># 报错</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-元组小结" tabindex="-1"><a class="header-anchor" href="#_3-元组小结" aria-hidden="true">#</a> (3) 元组小结</h4><ul><li>可以与列表一样使用for与while循环遍历</li><li>多数特性和list一致，不同点在于不可修改的特性</li><li>可以容纳多个数据</li><li>可以容纳不同类型的数据（混装）</li><li>数据是有序存储的（下标索引）</li><li>允许重复数据存在</li><li><strong>不可以修改</strong>（增加或删除元素等）</li></ul><hr><h3 id="四-字符串-str" tabindex="-1"><a class="header-anchor" href="#四-字符串-str" aria-hidden="true">#</a> 四.字符串(str)</h3><blockquote><p>字符串是字符的容器，一个字符串可以存放任意数量的字符。</p></blockquote><ul><li>同元组一样,字符串是一个无法修改的数据容器</li></ul><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/ead056ece8249be47382e4fbbb01e48d.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h4 id="_1-索引取值" tabindex="-1"><a class="header-anchor" href="#_1-索引取值" aria-hidden="true">#</a> (1) 索引取值</h4><ul><li>同列表、元组一样，字符串也可以通过下标进行访问 <ul><li>从前向后，下标从0开始</li><li>从后向前，下标从-1开始</li></ul></li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;guanzhi&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 g</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">[</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 i</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-字符串的常用操作" tabindex="-1"><a class="header-anchor" href="#_2-字符串的常用操作" aria-hidden="true">#</a> (2) 字符串的常用操作</h4><table><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">字符串[下标]</td><td style="text-align:left;">根据下标索引取出特定位置字符</td></tr><tr><td style="text-align:left;">字符串.index(字符串）</td><td style="text-align:left;">查找给定字符的第一个匹配项的下标</td></tr><tr><td style="text-align:left;">字符串.replace(字符串1, 字符串2)</td><td style="text-align:left;">将字符串内的全部字符串1，替换为字符串2 不会修改原字符串，而是得到一个新的</td></tr><tr><td style="text-align:left;">字符串.split(字符串)</td><td style="text-align:left;">按照给定字符串，对字符串进行分隔 不会修改原字符串，而是得到一个新的列表</td></tr><tr><td style="text-align:left;">字符串.strip() 字符串.strip(字符串)</td><td style="text-align:left;">移除首尾的空格和换行符或指定字符串</td></tr><tr><td style="text-align:left;">字符串.count(字符串)</td><td style="text-align:left;">统计字符串内某字符串的出现次数</td></tr><tr><td style="text-align:left;">len(字符串)</td><td style="text-align:left;">统计字符串的字符个数</td></tr></tbody></table><h5 id="_2-1-查找元素" tabindex="-1"><a class="header-anchor" href="#_2-1-查找元素" aria-hidden="true">#</a> (2.1) 查找元素</h5><blockquote><p>查找特定字符串的下标索引值</p></blockquote><ul><li>语法：字符串.index(字符串)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;guanzhi&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">.</span>index<span class="token punctuation">(</span><span class="token string">&quot;a&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 2</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-2-替换元素" tabindex="-1"><a class="header-anchor" href="#_2-2-替换元素" aria-hidden="true">#</a> (2.2) 替换元素</h5><blockquote><p>将字符串内的全部：字符串1，替换为字符串2</p></blockquote><ul><li>语法：字符串.replace(字符串1，字符串2）</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;guanzhi&quot;</span>
new_name <span class="token operator">=</span> name<span class="token punctuation">.</span>replace<span class="token punctuation">(</span><span class="token string">&quot;guan&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;study&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">)</span>  <span class="token comment"># 打印 guanzhi</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_name<span class="token punctuation">)</span>  <span class="token comment"># 打印 studyzhi</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>不是修改字符串本身，而是得到了一个新字符串</li></ul><h5 id="_2-3-分割元素" tabindex="-1"><a class="header-anchor" href="#_2-3-分割元素" aria-hidden="true">#</a> (2.3) 分割元素</h5><blockquote><p>按照指定的分隔符字符串，将字符串划分为多个字符串，并存入列表对象中</p></blockquote><ul><li>语法：字符串.split(分隔符字符串）</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;guanzhi,study,20&quot;</span>
new_list <span class="token operator">=</span> name<span class="token punctuation">.</span>split<span class="token punctuation">(</span><span class="token string">&quot;,&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">)</span>  <span class="token comment"># 打印 guanzhi,study,20</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_list<span class="token punctuation">)</span>  <span class="token comment"># 打印 [&#39;guanzhi&#39;, &#39;study&#39;, &#39;20&#39;]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>new_list<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;list&#39;&gt;</span>
<span class="token comment"># 字符串按照给定的,进行了分割，变成多个子字符串，并存入一个列表对象中</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>字符串本身不变，而是得到了一个列表对象</li></ul><h5 id="_2-4-规整操作" tabindex="-1"><a class="header-anchor" href="#_2-4-规整操作" aria-hidden="true">#</a> (2.4) 规整操作</h5><ul><li>去前后空格以及换行符</li><li>语法一：字符串.strip()</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;  guanzhi  &quot;</span>
new_name <span class="token operator">=</span> name<span class="token punctuation">.</span>strip<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_name<span class="token punctuation">)</span>  <span class="token comment"># 打印 guanzhi</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>去前后指定字符串</li><li>语法二：字符串.strip(字符串)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;20guanzhi20&quot;</span>
new_name <span class="token operator">=</span> name<span class="token punctuation">.</span>strip<span class="token punctuation">(</span><span class="token string">&quot;20&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">)</span>  <span class="token comment"># 打印 20guanzhi20</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_name<span class="token punctuation">)</span>  <span class="token comment"># 打印 guanzhi</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>字符串本身不变，而是得到了一个新字符串</li></ul><h5 id="_2-5-统计操作" tabindex="-1"><a class="header-anchor" href="#_2-5-统计操作" aria-hidden="true">#</a> (2.5) 统计操作</h5><ul><li>统计字符串中某字符串的出现次数</li><li>语法一：字符串.count(字符串)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;20guanzhi20&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">.</span>count<span class="token punctuation">(</span><span class="token string">&quot;20&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 2</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>统计字符串的长度</li><li>语法二：len(字符串)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>name <span class="token operator">=</span> <span class="token string">&quot;20guanzhi 20&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>name<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 12</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>数字（1、2、3…），字母（abcd、ABCD等），符号（空格、!、@、#、$等），中文均算作1个字符</li></ul><h4 id="_3-字符串小结" tabindex="-1"><a class="header-anchor" href="#_3-字符串小结" aria-hidden="true">#</a> (3) 字符串小结</h4><ul><li>同列表、元组一样，字符串也支持while循环和for循环进行遍历</li><li>特点： <ul><li>只可以存储字符串</li><li>长度任意（取决于内存大小）</li><li>支持下标索引</li><li>允许重复字符串存在</li><li>不可以修改（增加或删除元素等）</li></ul></li><li>基本和列表、元组相同 <ul><li>不同与列表和元组的在于：字符串容器可以容纳的类型是<strong>单一</strong>的，只能是字符串类型。</li><li>不同于列表，相同于元组的在于：字符串不可修改</li></ul></li></ul><hr><h3 id="五-数据容器-序列-的切片" tabindex="-1"><a class="header-anchor" href="#五-数据容器-序列-的切片" aria-hidden="true">#</a> 五.数据容器（序列）的切片</h3><blockquote><p>序列：内容连续、有序，可使用下标索引的一类数据容器</p><p>切片：从一个序列中，取出一个子序列</p></blockquote><ul><li>序列的典型特征就是：有序并可用下标索引，字符串、元组、列表均满足这个要求</li><li>序列支持切片，即：列表、元组、字符串，均支持进行切片操作</li></ul><h5 id="_1-基本格式-2" tabindex="-1"><a class="header-anchor" href="#_1-基本格式-2" aria-hidden="true">#</a> (1) 基本格式</h5><ul><li>语法：序列[起始下标:结束下标:步长]</li><li>表示从序列中，从指定位置开始，依次取出元素，到指定位置结束，得到一个新序列：</li><li><strong>起始下标</strong>表示从何处开始，可以留空，留空视作从头开始</li><li><strong>结束下标</strong>（不含）表示何处结束，可以留空，留空视作截取到结尾</li><li><strong>步长</strong>表示，依次取元素的间隔 <ul><li>步长1表示，一个个取元素</li><li>步长2表示，每次跳过<em>1个元素取</em></li><li><em>步长</em>N表示，每次跳过N-1个元素取</li><li>步长为负数表示，反向取（注意，起始下标和结束下标也要反向标记）</li></ul></li></ul><h5 id="_2-基本用法" tabindex="-1"><a class="header-anchor" href="#_2-基本用法" aria-hidden="true">#</a> (2) 基本用法</h5><ul><li>用法 <ul><li>起始下标可以省略，省略从头开始</li><li>结束下标可以省略，省略到尾结束</li><li>步长可以省略，省略步长为1（可以为负数，表示倒序执行）</li></ul></li><li>用法一：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>
new_list <span class="token operator">=</span> my_list<span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">:</span><span class="token number">4</span><span class="token punctuation">]</span>  <span class="token comment"># 下标1开始，下标4（不含）结束，步长1</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_list<span class="token punctuation">)</span>  <span class="token comment"># 结果：[2, 3, 4]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>用法二：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span>
new_tuple <span class="token operator">=</span> my_tuple<span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token punctuation">]</span>  <span class="token comment"># 从头开始，到最后结束，步长1</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_tuple<span class="token punctuation">)</span>  <span class="token comment"># 结果：(1, 2, 3, 4, 5)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>用法三：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>
new_list <span class="token operator">=</span> my_list<span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token punctuation">:</span><span class="token number">2</span><span class="token punctuation">]</span>       <span class="token comment"># 从头开始，到最后结束，步长2</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_list<span class="token punctuation">)</span>       <span class="token comment"># 结果：[1, 3, 5]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>用法四：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_str <span class="token operator">=</span> <span class="token string">&quot;12345&quot;</span>
new_str <span class="token operator">=</span> my_str<span class="token punctuation">[</span><span class="token punctuation">:</span><span class="token number">4</span><span class="token punctuation">:</span><span class="token number">2</span><span class="token punctuation">]</span>  <span class="token comment"># 从头开始，到下标4（不含）结束，步长2</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_str<span class="token punctuation">)</span>  <span class="token comment"># 结果：&quot;13&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>用法五：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">]</span>
new_list <span class="token operator">=</span> my_list<span class="token punctuation">[</span><span class="token number">3</span><span class="token punctuation">:</span><span class="token number">1</span><span class="token punctuation">:</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">]</span>  <span class="token comment"># 从下标3开始，到下标1（不含）结束，步长-1（倒序）</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>new_list<span class="token punctuation">)</span>  <span class="token comment"># 打印 [4, 3]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>注： <ul><li>这个操作对列表、元组、字符串是通用的</li><li>此操作不会影响序列本身，而是会得到一个新的序列（列表、元组、字符串）</li><li>起始位置，结束位置，步长（正反序）都是可以自行控制的</li></ul></li></ul><hr><h3 id="六-集合-set" tabindex="-1"><a class="header-anchor" href="#六-集合-set" aria-hidden="true">#</a> 六.集合(set)</h3><blockquote><p>不支持元素的重复（自带去重功能）、并且内容无序</p></blockquote><h4 id="_1-基本格式-3" tabindex="-1"><a class="header-anchor" href="#_1-基本格式-3" aria-hidden="true">#</a> (1) 基本格式</h4><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 定义集合</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">{</span>元素<span class="token number">1</span><span class="token punctuation">,</span> 元素<span class="token number">2</span><span class="token punctuation">,</span> 元素<span class="token number">3</span><span class="token punctuation">,</span> 元素<span class="token number">4</span><span class="token punctuation">,</span> 元素<span class="token number">5</span><span class="token punctuation">}</span>
<span class="token comment"># 定义空集合</span>
变量名称 <span class="token operator">=</span> <span class="token builtin">set</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>以大括号 {} 作为标识</li><li>集合内每一个元素之间用, 逗号隔开</li><li>集合可以一次存储多个数据，且可以为<strong>不同的数据类型</strong>，支持嵌套</li><li>使用示例：</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set<span class="token punctuation">)</span>  <span class="token comment"># 打印 {True, &#39;观止&#39;}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>去重且无序</li></ul><h4 id="_2-集合的遍历" tabindex="-1"><a class="header-anchor" href="#_2-集合的遍历" aria-hidden="true">#</a> (2) 集合的遍历</h4><blockquote><p>集合不支持下标索引，所以也就不支持使用while。</p></blockquote><ul><li>因为集合是无序的，所以集合不支持下标索引访问</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">}</span>
<span class="token keyword">for</span> i <span class="token keyword">in</span> my_set<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span>
<span class="token comment"># 打印</span>
<span class="token comment"># True</span>
<span class="token comment"># 观止</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-集合的常用操作" tabindex="-1"><a class="header-anchor" href="#_3-集合的常用操作" aria-hidden="true">#</a> (3) 集合的常用操作</h4><table><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">集合.add(元素)</td><td style="text-align:left;">集合内添加一个元素</td></tr><tr><td style="text-align:left;">集合.remove(元素)</td><td style="text-align:left;">移除集合内指定的元素</td></tr><tr><td style="text-align:left;">集合.pop()</td><td style="text-align:left;">从集合中随机取出一个元素</td></tr><tr><td style="text-align:left;">集合.clear()</td><td style="text-align:left;">将集合清空</td></tr><tr><td style="text-align:left;">集合1.difference(集合2)</td><td style="text-align:left;">得到一个新集合，内含2个集合的差集 原有的2个集合内容不变</td></tr><tr><td style="text-align:left;">集合1.difference_update(集合2)</td><td style="text-align:left;">在集合1中，删除集合2中存在的元素 集合1被修改，集合2不变</td></tr><tr><td style="text-align:left;">集合1.union(集合2)</td><td style="text-align:left;">得到1个新集合，内含2个集合的全部元素 原有的2个集合内容不变</td></tr><tr><td style="text-align:left;">len(集合)</td><td style="text-align:left;">得到一个整数，记录了集合的元素数量</td></tr></tbody></table><h5 id="_3-1-增加元素" tabindex="-1"><a class="header-anchor" href="#_3-1-增加元素" aria-hidden="true">#</a> (3.1) 增加元素</h5><ul><li>集合本身被修改，将指定元素，添加到集合内</li><li>语法：集合.add(元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">}</span>
my_set<span class="token punctuation">.</span>add<span class="token punctuation">(</span><span class="token string">&quot;study&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set<span class="token punctuation">)</span>  <span class="token comment"># 打印 {&#39;观止&#39;, True, &#39;study&#39;}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-2-移除元素" tabindex="-1"><a class="header-anchor" href="#_3-2-移除元素" aria-hidden="true">#</a> (3.2) 移除元素</h5><ul><li>集合本身被修改，将指定元素，从集合内移除</li><li>语法一：集合.remove(元素)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">}</span>
my_set<span class="token punctuation">.</span>remove<span class="token punctuation">(</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set<span class="token punctuation">)</span>  <span class="token comment"># 打印 {True}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><p>从集合中随机取出一个元素，同时集合本身被修改，元素被移除</p></li><li><p>语法二：集合.pop()</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">}</span>
num <span class="token operator">=</span> my_set<span class="token punctuation">.</span>pop<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set<span class="token punctuation">)</span>  <span class="token comment"># 打印 {&#39;观止&#39;}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>num<span class="token punctuation">)</span>  <span class="token comment"># 打印 True</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li><p>清空集合,集合本身被清空</p></li><li><p>语法三：集合.clear()</p></li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">,</span> <span class="token boolean">True</span><span class="token punctuation">}</span>
my_set<span class="token punctuation">.</span>clear<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set<span class="token punctuation">)</span>  <span class="token comment"># 打印 set()</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-3-两集合操作" tabindex="-1"><a class="header-anchor" href="#_3-3-两集合操作" aria-hidden="true">#</a> (3.3) 两集合操作</h5><ul><li>取出集合1和集合2的差集（集合1有而集合2没有的)，得到一个新集合，集合1和集合2不变</li><li>语法一：集合1.difference(集合2)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set_1 <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">}</span>
my_set_2 <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">}</span>
my_set_3 <span class="token operator">=</span> my_set_1<span class="token punctuation">.</span>difference<span class="token punctuation">(</span>my_set_2<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_1<span class="token punctuation">)</span>  <span class="token comment"># 打印 {1, 2}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_2<span class="token punctuation">)</span>  <span class="token comment"># 打印 {1, 3}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_3<span class="token punctuation">)</span>  <span class="token comment"># 打印 {2}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>对比集合1和集合2，在集合1内，删除和集合2相同的元素,集合1被修改，集合2不变</li><li>语法二：集合1.difference_update(集合2)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set_1 <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">}</span>
my_set_2 <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">}</span>
my_set_1<span class="token punctuation">.</span>difference_update<span class="token punctuation">(</span>my_set_2<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_1<span class="token punctuation">)</span>  <span class="token comment"># 打印 {2}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_2<span class="token punctuation">)</span>  <span class="token comment"># 打印 {1, 3}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>将集合1和集合2组合成新集合(去重)，集合1和集合2不变</li><li>语法三：集合1.union(集合2)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set_1 <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">}</span>
my_set_2 <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">}</span>
my_set_3 <span class="token operator">=</span> my_set_1<span class="token punctuation">.</span>union<span class="token punctuation">(</span>my_set_2<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_1<span class="token punctuation">)</span>  <span class="token comment"># 打印 {1, 2}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_2<span class="token punctuation">)</span>  <span class="token comment"># 打印 {1, 3}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_set_3<span class="token punctuation">)</span>  <span class="token comment"># 打印 {1, 2, 3}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-4-集合长度" tabindex="-1"><a class="header-anchor" href="#_3-4-集合长度" aria-hidden="true">#</a> (3.4) 集合长度</h5><ul><li>查看集合的元素数量，统计集合内有多少元素</li><li>语法四：len(集合)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_set <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>my_set<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 2</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-集合小结" tabindex="-1"><a class="header-anchor" href="#_4-集合小结" aria-hidden="true">#</a> (4) 集合小结</h4><ul><li>特点： <ul><li>可以容纳多个数据</li><li>可以容纳不同类型的数据（混装）</li><li>数据是无序存储的（不支持下标索引）</li><li>不允许重复数据存在</li><li>可以修改（增加或删除元素等）</li></ul></li></ul><hr><h3 id="七-字典、映射-dict" tabindex="-1"><a class="header-anchor" href="#七-字典、映射-dict" aria-hidden="true">#</a> 七.字典、映射(dict)</h3><blockquote><p>Python中字典和生活中字典十分相像</p></blockquote><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/ef6ebf60198cc812cd262baa070bc52b.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h4 id="_1-基本格式-4" tabindex="-1"><a class="header-anchor" href="#_1-基本格式-4" aria-hidden="true">#</a> (1) 基本格式</h4><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># 定义字典</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">{</span>key<span class="token punctuation">:</span>value<span class="token punctuation">,</span> key<span class="token punctuation">:</span>value<span class="token punctuation">,</span> key<span class="token punctuation">:</span>value<span class="token punctuation">}</span>
<span class="token comment"># 定义空字典</span>
变量名称 <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
变量名称 <span class="token operator">=</span> <span class="token builtin">dict</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>使用{}存储原始，每一个元素是一个键值对</li><li>每一个键值对包含Key和Value（用冒号分隔）</li><li>键值对之间使用逗号分隔</li><li>Key和Value可以是任意类型的数据（key不可为字典）</li><li>Key不可重复，重复会对原有数据覆盖</li><li>使用示例:</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">99</span><span class="token punctuation">,</span> <span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">)</span>  <span class="token comment"># 打印 {&#39;观止&#39;: 110, &#39;李白&#39;: 120}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印  &lt;class &#39;dict&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_2-数据的获取" tabindex="-1"><a class="header-anchor" href="#_2-数据的获取" aria-hidden="true">#</a> (2) 数据的获取</h4><ul><li>字典同集合一样，不可以使用下标索引取值</li><li>字典可以通过Key值来取得对应的Value</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 120</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>字典的Key和Value可以是任意数据类型（Key不可为字典）,即字典是可以嵌套的</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span>
    <span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;语文&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">,</span> <span class="token string">&quot;数学&quot;</span><span class="token punctuation">:</span> <span class="token number">100</span><span class="token punctuation">}</span><span class="token punctuation">,</span> 
    <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token punctuation">{</span><span class="token string">&quot;语文&quot;</span><span class="token punctuation">:</span> <span class="token number">90</span><span class="token punctuation">,</span> <span class="token string">&quot;数学&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 {&#39;语文&#39;: 110, &#39;数学&#39;: 100}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token string">&quot;语文&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 110</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>字典不支持下标索引，同样不可以用while循环遍历</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
<span class="token keyword">for</span> name <span class="token keyword">in</span> my_dict<span class="token punctuation">:</span>
    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&quot;key为：</span><span class="token interpolation"><span class="token punctuation">{</span>name<span class="token punctuation">}</span></span><span class="token string">,value为：</span><span class="token interpolation"><span class="token punctuation">{</span>my_dict<span class="token punctuation">[</span>name<span class="token punctuation">]</span><span class="token punctuation">}</span></span><span class="token string">&quot;</span></span><span class="token punctuation">)</span>
<span class="token comment"># 打印</span>
<span class="token comment"># key为：李白,value为：120</span>
<span class="token comment"># key为：观止,value为：110</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-字典的常用操作" tabindex="-1"><a class="header-anchor" href="#_3-字典的常用操作" aria-hidden="true">#</a> (3) 字典的常用操作</h4><table><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">字典[Key]</td><td style="text-align:left;">获取指定Key对应的Value值</td></tr><tr><td style="text-align:left;">字典[Key] = Value</td><td style="text-align:left;">添加或更新键值对</td></tr><tr><td style="text-align:left;">字典.pop(Key)</td><td style="text-align:left;">取出Key对应的Value并在字典内删除此Key的键值对</td></tr><tr><td style="text-align:left;">字典.clear()</td><td style="text-align:left;">清空字典</td></tr><tr><td style="text-align:left;">字典.keys()</td><td style="text-align:left;">获取字典的全部Key，可用于for循环遍历字典</td></tr><tr><td style="text-align:left;">len(字典)</td><td style="text-align:left;">计算字典内的元素数量</td></tr></tbody></table><h5 id="_3-1-新增元素" tabindex="-1"><a class="header-anchor" href="#_3-1-新增元素" aria-hidden="true">#</a> (3.1) 新增元素</h5><ul><li>字典被修改，新增了元素</li><li>如果key不存在字典中执行上述操作，就是新增元素</li><li>语法：字典[Key] = Value</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
my_dict<span class="token punctuation">[</span><span class="token string">&quot;罗辑&quot;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">115</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">)</span>  <span class="token comment"># 打印 {&#39;李白&#39;: 120, &#39;观止&#39;: 110, &#39;罗辑&#39;: 115}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-2-更新元素" tabindex="-1"><a class="header-anchor" href="#_3-2-更新元素" aria-hidden="true">#</a> (3.2) 更新元素</h5><ul><li>字典被修改，元素被更新</li><li>字典Key不可以重复，所以对已存在的Key执行上述操作，就是更新Value值</li><li>语法：字典[Key] = Value</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
my_dict<span class="token punctuation">[</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token number">115</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">)</span>  <span class="token comment"># 打印 {&#39;李白&#39;: 115, &#39;观止&#39;: 110}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-3-删除元素" tabindex="-1"><a class="header-anchor" href="#_3-3-删除元素" aria-hidden="true">#</a> (3.3) 删除元素</h5><ul><li>获得指定Key的Value，同时字典被修改，指定Key的数据被删除</li><li>语法：字典.pop(Key)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
name <span class="token operator">=</span> my_dict<span class="token punctuation">.</span>pop<span class="token punctuation">(</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>name<span class="token punctuation">)</span>  <span class="token comment"># 打印 120</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">)</span>  <span class="token comment"># 打印 {&#39;观止&#39;: 110}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-4-清空字典" tabindex="-1"><a class="header-anchor" href="#_3-4-清空字典" aria-hidden="true">#</a> (3.4) 清空字典</h5><ul><li>字典被修改，元素被清空</li><li>语法：字典.clear()</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
my_dict<span class="token punctuation">.</span>clear<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">)</span>  <span class="token comment"># 打印 {}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-5-获取全部的key" tabindex="-1"><a class="header-anchor" href="#_3-5-获取全部的key" aria-hidden="true">#</a> (3.5) 获取全部的key</h5><ul><li>得到字典中的全部Key</li><li>语法：字典.keys()</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
my_keys <span class="token operator">=</span> my_dict<span class="token punctuation">.</span>keys<span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_keys<span class="token punctuation">)</span>  <span class="token comment"># 打印 dict_keys([&#39;李白&#39;, &#39;观止&#39;])</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-6-计算字典内键值对数量" tabindex="-1"><a class="header-anchor" href="#_3-6-计算字典内键值对数量" aria-hidden="true">#</a> (3.6) 计算字典内键值对数量</h5><ul><li>得到一个整数，表示字典内元素（键值对）的数量</li><li>语法：len(字典)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_dict <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token string">&quot;李白&quot;</span><span class="token punctuation">:</span> <span class="token number">120</span><span class="token punctuation">,</span> <span class="token string">&quot;观止&quot;</span><span class="token punctuation">:</span> <span class="token number">110</span><span class="token punctuation">}</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>my_dict<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 2</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_4-字典小结" tabindex="-1"><a class="header-anchor" href="#_4-字典小结" aria-hidden="true">#</a> (4) 字典小结</h4><ul><li>特点： <ul><li>可以容纳多个数据</li><li>可以容纳不同类型的数据</li><li>每一份数据是Key-Value键值对</li><li>可以通过Key获取到Value，Key不可重复（重复会覆盖）</li><li>不支持下标索引</li><li>可以修改（增加或删除更新元素等）</li></ul></li></ul><hr><h3 id="八-数据容器对比总结" tabindex="-1"><a class="header-anchor" href="#八-数据容器对比总结" aria-hidden="true">#</a> 八.数据容器对比总结</h3><h4 id="_1-简单分类" tabindex="-1"><a class="header-anchor" href="#_1-简单分类" aria-hidden="true">#</a> (1) 简单分类</h4><ul><li>是否支持下标索引 <ul><li>支持：列表、元组、字符串 - 序列类型</li><li>不支持：集合、字典 - 非序列类型</li></ul></li><li>是否支持重复元素： <ul><li>支持：列表、元组、字符串 - 序列类型</li><li>不支持：集合、字典 - 非序列类型</li></ul></li><li>是否可以修改 <ul><li>支持：列表、集合、字典</li><li>不支持：元组、字符串</li></ul></li></ul><h4 id="_2-特点对比" tabindex="-1"><a class="header-anchor" href="#_2-特点对比" aria-hidden="true">#</a> (2) 特点对比</h4><table><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">列表</th><th style="text-align:left;">元组</th><th style="text-align:left;">字符串</th><th style="text-align:left;">集合</th><th style="text-align:left;">字典</th></tr></thead><tbody><tr><td style="text-align:left;">元素数量</td><td style="text-align:left;">支持多个</td><td style="text-align:left;">支持多个</td><td style="text-align:left;">支持多个</td><td style="text-align:left;">支持多个</td><td style="text-align:left;">支持多个</td></tr><tr><td style="text-align:left;">元素类型</td><td style="text-align:left;">任意</td><td style="text-align:left;">任意</td><td style="text-align:left;">仅字符</td><td style="text-align:left;">任意</td><td style="text-align:left;">Key：Value Key：除字典外任意类型 Value：任意类型</td></tr><tr><td style="text-align:left;">下标索引</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td><td style="text-align:left;">不支持</td><td style="text-align:left;">不支持</td></tr><tr><td style="text-align:left;">重复元素</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td><td style="text-align:left;">不支持</td><td style="text-align:left;">不支持</td></tr><tr><td style="text-align:left;">可修改性</td><td style="text-align:left;">支持</td><td style="text-align:left;">不支持</td><td style="text-align:left;">不支持</td><td style="text-align:left;">支持</td><td style="text-align:left;">支持</td></tr><tr><td style="text-align:left;">数据有序</td><td style="text-align:left;">是</td><td style="text-align:left;">是</td><td style="text-align:left;">是</td><td style="text-align:left;">否</td><td style="text-align:left;">否</td></tr><tr><td style="text-align:left;">使用场景</td><td style="text-align:left;">可修改、可重复的一批数据记录场景</td><td style="text-align:left;">不可修改、可重复的一批数据记录场景</td><td style="text-align:left;">一串字符的记录场景</td><td style="text-align:left;">不可重复的数据记录场景</td><td style="text-align:left;">以Key检索Value的数据记录场景</td></tr></tbody></table><h4 id="_3-应用场景" tabindex="-1"><a class="header-anchor" href="#_3-应用场景" aria-hidden="true">#</a> (3) 应用场景</h4><ul><li>列表：一批数据，可修改、可重复的存储场景</li><li>元组：一批数据，不可修改、可重复的存储场景</li><li>字符串：一串字符串的存储场景</li><li>集合：一批数据，去重存储场景</li><li>字典：一批数据，可用Key检索Value的存储场景</li></ul><table><thead><tr><th style="text-align:left;">功能</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">通用for循环</td><td style="text-align:left;">遍历容器（字典是遍历key）</td></tr><tr><td style="text-align:left;">max</td><td style="text-align:left;">容器内最大元素</td></tr><tr><td style="text-align:left;">min()</td><td style="text-align:left;">容器内最小元素</td></tr><tr><td style="text-align:left;">len()</td><td style="text-align:left;">容器元素个数</td></tr><tr><td style="text-align:left;">list()</td><td style="text-align:left;">转换为列表</td></tr><tr><td style="text-align:left;">tuple()</td><td style="text-align:left;">转换为元组</td></tr><tr><td style="text-align:left;">str()</td><td style="text-align:left;">转换为字符串</td></tr><tr><td style="text-align:left;">set()</td><td style="text-align:left;">转换为集合</td></tr><tr><td style="text-align:left;">sorted(序列, [reverse=True])</td><td style="text-align:left;">排序，reverse=True表示降序 得到一个排好序的列表</td></tr></tbody></table><h4 id="_4-通用操作-遍历" tabindex="-1"><a class="header-anchor" href="#_4-通用操作-遍历" aria-hidden="true">#</a> (4) 通用操作-遍历</h4><ul><li>5类数据容器都支持for循环遍历</li><li>列表、元组、字符串支持while循环，集合、字典不支持（无法下标索引）</li></ul><h4 id="_5-通用操作-统计" tabindex="-1"><a class="header-anchor" href="#_5-通用操作-统计" aria-hidden="true">#</a> (5) 通用操作-统计</h4><h5 id="_5-1-统计容器的元素个数" tabindex="-1"><a class="header-anchor" href="#_5-1-统计容器的元素个数" aria-hidden="true">#</a> (5.1)统计容器的元素个数</h5><ul><li>语法：len(容器)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span>
my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span>
my_str <span class="token operator">=</span> <span class="token string">&quot;guanzhi&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 3</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 5</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">len</span><span class="token punctuation">(</span>my_str<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 7</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_5-2-统计容器的最大元素" tabindex="-1"><a class="header-anchor" href="#_5-2-统计容器的最大元素" aria-hidden="true">#</a> (5.2) 统计容器的最大元素</h5><ul><li>语法：max(容器)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span>
my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span>
my_str <span class="token operator">=</span> <span class="token string">&quot;guanzhi&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">max</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 3</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">max</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 5</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">max</span><span class="token punctuation">(</span>my_str<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 z</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_5-3-统计容器的最小元素" tabindex="-1"><a class="header-anchor" href="#_5-3-统计容器的最小元素" aria-hidden="true">#</a> (5.3) 统计容器的最小元素</h5><ul><li>语法：min(容器)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">]</span>
my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token punctuation">)</span>
my_str <span class="token operator">=</span> <span class="token string">&quot;guanzhi&quot;</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">min</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 1</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">min</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 1</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">min</span><span class="token punctuation">(</span>my_str<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 结果 a</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_5-4-字符串大小比较" tabindex="-1"><a class="header-anchor" href="#_5-4-字符串大小比较" aria-hidden="true">#</a> (5.4) 字符串大小比较</h5><ul><li>ASCII码表：</li></ul><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/4a1cbe5ff75ddcd05724b471b1850241.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>在程序中，字符串所用的所有字符如：大小写，英文单词，数字特殊符号(!、\\、|、@、#、空格等），都有其对应的ASCII码表值</li><li>每一个字符都能对应上一个：数字的码值，字符串进行比较就是基于数字的码值大小进行比较的。</li><li>字符串是按位比较，也就是一位位进行对比，只要有一位大，那么整体就大:</li></ul><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/00ecd88257e836aac34055783e13e6f6.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h4 id="_6-通用操作-排序" tabindex="-1"><a class="header-anchor" href="#_6-通用操作-排序" aria-hidden="true">#</a> (6) 通用操作-排序</h4><ul><li><p>将给定容器进行排序,排序后都会得到列表（list）对象。</p></li><li><p>语法:sorted(容器, [reverse=True])</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">]</span>
my_list_asc <span class="token operator">=</span> <span class="token builtin">sorted</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list_asc<span class="token punctuation">)</span>  <span class="token comment"># 结果 [1, 2, 4]</span>
my_list_des <span class="token operator">=</span> <span class="token builtin">sorted</span><span class="token punctuation">(</span>my_list<span class="token punctuation">,</span> reverse<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>my_list_des<span class="token punctuation">)</span>  <span class="token comment"># 结果 [4, 2, 1]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ul><h4 id="_7-通用操作-转换" tabindex="-1"><a class="header-anchor" href="#_7-通用操作-转换" aria-hidden="true">#</a> (7) 通用操作-转换</h4><ul><li>将给定容器转换为列表</li><li>语法一：list(容器)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span> 
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;tuple&#39;&gt;</span>
my_list <span class="token operator">=</span> <span class="token builtin">list</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;list&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>将给定容器转换为字符串</li><li>语法二：str(容器)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;tuple&#39;&gt;</span>
my_str <span class="token operator">=</span> <span class="token builtin">str</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_str<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;str&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>将给定容器转换为集合</li><li>语法三：set(容器)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_tuple <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;tuple&#39;&gt;</span>
my_set <span class="token operator">=</span> <span class="token builtin">set</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_set<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;set&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>将给定容器转换为元组</li><li>语法四：tuple(容器)</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>my_list <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">4</span><span class="token punctuation">,</span> <span class="token number">2</span><span class="token punctuation">]</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;list&#39;&gt;</span>
my_tuple <span class="token operator">=</span> <span class="token builtin">tuple</span><span class="token punctuation">(</span>my_list<span class="token punctuation">)</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>my_tuple<span class="token punctuation">)</span><span class="token punctuation">)</span>  <span class="token comment"># 打印 &lt;class &#39;tuple&#39;&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="全文概览" tabindex="-1"><a class="header-anchor" href="#全文概览" aria-hidden="true">#</a> 全文概览</h3><figure><img src="https://gitlab.com/apzs/apzs/-/raw/master/python/image/d731a96fba2478d163b31702830a2f1a.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure>`,278);function b(h,y){const a=p("ExternalLinkIcon");return l(),o("div",null,[u,n("blockquote",null,[n("p",null,[s("python学习之旅（五） 学习汇总入口"),n("a",r,[s("【Python】学习汇总(3万字+思维导图)"),t(a)]),s(" 笔记PDF下载："),n("a",d,[s("知识笔记：Python数据容器(五)"),t(a)]),s(" 文末附带全文概览思维导图 写作不易，如果您觉得写的不错，欢迎给博主来一波点赞、收藏~让博主更有动力吧！")])]),k,n("blockquote",null,[n("p",null,[s("一种可以容纳多份数据的"),n("a",m,[s("数据类型"),t(a)]),s("，容纳的每一份数据称之为1个元素")])]),v])}const x=e(c,[["render",b],["__file","05.数据容器.html.vue"]]);export{x as default};
